pub const MODEL_ID: &str = "lv2_artyfx_bad_masha";
pub const DISPLAY_NAME: &str = "Masha";
const BRAND: &str = "openav";

const PLUGIN_URI: &str = "http://www.openavproductions.com/artyfx#masha";
const PLUGIN_DIR: &str = "artyfx-bad";

#[cfg(target_os = "macos")]
const PLUGIN_BINARY: &str = "artyfx.dylib";
#[cfg(target_os = "linux")]
const PLUGIN_BINARY: &str = "artyfx.so";
#[cfg(target_os = "windows")]
const PLUGIN_BINARY: &str = "artyfx.dll";

// Port indices (from TTL)
const PORT_AUDIO_IN_IN_LEFT: usize = 0;
const PORT_AUDIO_IN_IN_RIGHT: usize = 1;
const PORT_AUDIO_OUT_OUT_LEFT: usize = 2;
const PORT_AUDIO_OUT_OUT_RIGHT: usize = 3;
const PORT_CTRL_TIME: usize = 4;
const PORT_CTRL_AMPLITUDE: usize = 5;
const PORT_CTRL_DRY_WET: usize = 6;
const PORT_CTRL_ACTIVE: usize = 7;
const PORT_ATOM_IN_CONTROL: usize = 8;

pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_DELAY.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::TrueStereo,
        parameters: vec![
            float_parameter("time", "Time", None, Some(0.5), 0.0, 1.0, 0.01, ParameterUnit::None),
            float_parameter("amplitude", "Amplitude", None, Some(1.0), 0.0, 1.0, 0.01, ParameterUnit::None),
            float_parameter("dry_wet", "Dry Wet Mix", None, Some(1.0), 0.0, 1.0, 0.01, ParameterUnit::None),
            bool_parameter("active", "Active", None, Some(true)),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let time = required_f32(params, "time").map_err(anyhow::Error::msg)?;
    let amplitude = required_f32(params, "amplitude").map_err(anyhow::Error::msg)?;
    let dry_wet = required_f32(params, "dry_wet").map_err(anyhow::Error::msg)?;
    let active = required_bool(params, "active").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_TIME, time),
        (PORT_CTRL_AMPLITUDE, amplitude),
        (PORT_CTRL_DRY_WET, dry_wet),
        (PORT_CTRL_ACTIVE, if active { 1.0 } else { 0.0 }),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN_LEFT, PORT_AUDIO_IN_IN_RIGHT], &[PORT_AUDIO_OUT_OUT_LEFT, PORT_AUDIO_OUT_OUT_RIGHT], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

fn schema() -> Result<ModelParameterSchema> { Ok(model_schema()) }

